  return (
    <article>
      <h1>{post.title}</h1>
      <p>{post.body}</p>
    </article>
  );
}

export default function PostPage({
  params,
}: {
  params: Promise<{ slug: string }>;
}) {
  return (
    <Suspense fallback={<p>読み込み中...</p>}>
      <PostContent params={params} />
    </Suspense>
  );
}
```

説明文も合わせて「Page 関数は `<Suspense>` を返す同期コンポーネントにし、`params` を await する処理は内側の async コンポーネント `PostContent` に分離します」に更新。

