  return (
    <article>
      {post.cover && (
        <Image
          src={post.cover}
          alt=""
          width={1200}
          height={600}
          preload
          sizes="(max-width: 768px) 100vw, 800px"
        />
      )}
      <h1>{post.title}</h1>
      <p>{post.body}</p>
    </article>
  );
}
```

